-- CCPA Right to Know (CC §1798.100)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_009', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.100', 'CC § 1798.100', 'CCPA Right to Know — Consumer Access to Personal Information', 'A consumer has the right to request that a business that collects personal information disclose the categories and specific pieces of personal information it has collected about that consumer. Businesses must disclose the categories of sources, the business or commercial purpose for collecting or selling, and the categories of third parties with whom the business shares personal information. Requests must be responded to within 45 days, with one 45-day extension permitted. Businesses must provide information for the preceding 12-month period and may not require a consumer to create an account to make a verifiable request.', '["Disclose categories of personal information collected","Disclose specific pieces of personal information collected","Disclose categories of sources from which PI was collected","Disclose business or commercial purpose for collecting/selling","Disclose categories of third parties with whom PI is shared","Respond to verifiable consumer requests within 45 days","May extend response period by additional 45 days with notice","Provide information for preceding 12-month period","Provide two or more designated methods for submitting requests","Free of charge for first two requests in a 12-month period"]', '[{"section":"1798.100(a)","description":"Right to request disclosure of personal information collected"},{"section":"1798.100(b)","description":"Business obligation to disclose upon verifiable request"},{"section":"1798.100(c)","description":"Prohibition on collecting additional categories without notice"},{"section":"1798.100(d)","description":"Requirement to provide information free of charge"}]', '["privacy_policy","consumer_request_form","data_inventory","DSAR_response","verifiable_consumer_request"]', '["privacy-data-protection-audit"]', 'California Attorney General / California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CCPA Right to Delete (CC §1798.105)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_010', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.105', 'CC § 1798.105', 'CCPA Right to Delete — Consumer Deletion Requests', 'A consumer has the right to request that a business delete any personal information about the consumer which the business has collected from the consumer. Upon receiving a verifiable consumer request, the business must delete the consumer''s personal information from its records and direct any service providers to delete the consumer''s personal information from their records. Nine statutory exceptions permit retention, including completing transactions, detecting security incidents, exercising free speech, complying with legal obligations, and internal uses reasonably aligned with consumer expectations.', '["Delete personal information upon verifiable consumer request","Direct service providers to delete consumer PI","Respond within 45 days of receiving request","Notify consumer of exceptions if deletion is denied","Nine statutory exceptions to deletion requirement","Must verify identity of consumer making request","Cannot require account creation for deletion request","Must provide at least two methods for submitting requests"]', '[{"section":"1798.105(a)","description":"Consumer right to request deletion"},{"section":"1798.105(b)","description":"Business obligation to comply and exceptions"},{"section":"1798.105(c)","description":"Business obligation to direct service provider deletion"},{"section":"1798.105(d)","description":"Enumerated exceptions to deletion"}]', '["deletion_request","DSAR_response","data_retention_policy","service_provider_agreement","deletion_confirmation"]', '["privacy-data-protection-audit"]', 'California Attorney General / California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CCPA Right to Opt-Out of Sale (CC §1798.120)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_011', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.120', 'CC § 1798.120', 'CCPA Right to Opt-Out of Sale of Personal Information', 'A consumer has the right, at any time, to direct a business that sells or shares personal information about the consumer to third parties not to sell or share the consumer''s personal information. Businesses must provide a clear and conspicuous "Do Not Sell or Share My Personal Information" link on their website homepage. Businesses must wait at least 12 months before requesting that a consumer who has opted out authorize the sale of their personal information again. Businesses may not sell the personal information of consumers under 16 without affirmative authorization.', '["Provide clear Do Not Sell or Share My Personal Information link","Honor opt-out requests immediately","Wait 12 months before requesting re-authorization to sell","Do not sell PI of consumers under 16 without opt-in consent","Consumers 13-15 must provide affirmative opt-in","Parent/guardian consent required for consumers under 13","Do not discriminate against consumers who opt out","Respect Global Privacy Control signals as valid opt-out"]', '[{"section":"1798.120(a)","description":"Consumer right to opt out of sale/sharing"},{"section":"1798.120(b)","description":"Business obligation to honor opt-out"},{"section":"1798.120(c)","description":"Prohibition on selling PI of minors without opt-in"},{"section":"1798.120(d)","description":"12-month waiting period before re-solicitation"}]', '["opt_out_request","privacy_policy","Do_Not_Sell_page","consent_record","GPC_signal_log","minor_consent_form"]', '["privacy-data-protection-audit"]', 'California Attorney General / California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CCPA Right to Non-Discrimination (CC §1798.125)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_012', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.125', 'CC § 1798.125', 'CCPA Right to Non-Discrimination for Exercising Privacy Rights', 'A business shall not discriminate against a consumer because the consumer exercised any of their CCPA rights. Prohibited discrimination includes denying goods or services, charging different prices or rates, providing a different level or quality of goods or services, or suggesting the consumer will receive a different price or quality. Businesses may offer financial incentives for the collection, sale, or deletion of personal information if the incentive is reasonably related to the value of the consumer''s data and disclosed in a notice of financial incentive.', '["Do not deny goods or services to consumers exercising rights","Do not charge different prices for exercising rights","Do not provide different quality or level of service","Do not suggest different treatment for exercising rights","Financial incentives must be reasonably related to data value","Financial incentive programs require opt-in consent","Notice of financial incentive must be provided","Consumer may withdraw from incentive program at any time"]', '[{"section":"1798.125(a)(1)","description":"Prohibition on discriminatory practices"},{"section":"1798.125(a)(2)","description":"Permitted price differentials related to data value"},{"section":"1798.125(b)(1)","description":"Financial incentive programs — opt-in requirement"},{"section":"1798.125(b)(2)","description":"Notice of financial incentive requirements"}]', '["non_discrimination_policy","financial_incentive_notice","pricing_policy","loyalty_program_terms","consumer_complaint"]', '["privacy-data-protection-audit"]', 'California Attorney General / California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CPRA Amendments — Right to Correct (CC §1798.106)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_013', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.106', 'CC § 1798.106', 'CPRA Right to Correct Inaccurate Personal Information', 'Added by the California Privacy Rights Act (CPRA, Proposition 24, effective January 1, 2023), this section grants consumers the right to request that a business correct inaccurate personal information that the business maintains about the consumer. Businesses must use commercially reasonable efforts to correct the information as directed by the consumer and must instruct service providers and contractors to make corrections in their records. Businesses may delay or deny correction if the request cannot be verified, but must explain the basis for denial.', '["Correct inaccurate personal information upon verified request","Use commercially reasonable efforts to make corrections","Instruct service providers and contractors to correct records","Respond to correction requests within 45 days","May extend response by additional 45 days with notice","Document basis for denial if correction is refused","Consider totality of circumstances in determining accuracy","Provide at least two designated methods for submitting requests"]', '[{"section":"1798.106(a)","description":"Consumer right to request correction of inaccurate PI"},{"section":"1798.106(b)","description":"Business obligation to correct upon verifiable request"},{"section":"1798.106(c)","description":"Commercially reasonable efforts standard"},{"section":"1798.106(d)","description":"Obligation to direct service provider correction"}]', '["correction_request","DSAR_response","data_quality_policy","service_provider_agreement","correction_confirmation"]', '["privacy-data-protection-audit"]', 'California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CPRA — Sensitive Personal Information (CC §1798.121)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_014', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.121', 'CC § 1798.121', 'CPRA Right to Limit Use and Disclosure of Sensitive Personal Information', 'Added by the CPRA, this section grants consumers the right to direct a business that collects sensitive personal information to limit its use to that which is necessary to perform the services or provide the goods reasonably expected by an average consumer. Sensitive PI includes Social Security numbers, driver''s license numbers, financial account information, precise geolocation, racial/ethnic origin, religious beliefs, union membership, mail/email/text contents, genetic data, biometric data, health information, and sex life/sexual orientation data. Businesses must provide a clear link titled "Limit the Use of My Sensitive Personal Information."', '["Provide Limit the Use of My Sensitive Personal Information link","Limit use of sensitive PI to what is necessary for expected services","Sensitive PI includes SSN, DL, financial accounts, precise geolocation","Sensitive PI includes race, religion, union membership, genetic/biometric data","Sensitive PI includes health data, sex life, mail/email/text contents","Do not use sensitive PI for profiling without consent","Direct service providers to limit use of sensitive PI","Honor limit requests immediately upon receipt"]', '[{"section":"1798.121(a)","description":"Consumer right to limit use of sensitive PI"},{"section":"1798.121(b)","description":"Business obligation to restrict processing upon request"},{"section":"1798.121(c)","description":"Service provider obligations regarding sensitive PI"},{"section":"1798.121(d)","description":"Exceptions for certain necessary processing"}]', '["sensitive_PI_inventory","limit_use_request","privacy_policy","consent_record","data_processing_agreement","Limit_Use_page"]', '["privacy-data-protection-audit"]', 'California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CCPA Service Provider Obligations (CC §1798.140(ag))
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_015', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.140(ag)', 'CC § 1798.140(ag)', 'CCPA Service Provider Obligations — Contractual and Processing Restrictions', 'A service provider is a person or entity that processes personal information on behalf of a business pursuant to a written contract. Service providers must not retain, use, or disclose personal information for any purpose other than performing the services specified in the contract, including retaining, using, or disclosing PI for a commercial purpose other than providing the contracted services. The written contract must prohibit the service provider from selling or sharing the PI, combining PI received from the business with PI from other sources, and using PI outside the direct business relationship.', '["Written contract required between business and service provider","Prohibit retention/use/disclosure outside contracted services","Prohibit selling or sharing received personal information","Prohibit combining PI with data from other sources","Certify understanding of CCPA restrictions","Permit business to monitor compliance","Notify business if unable to meet CCPA obligations","Cooperate with consumer rights requests from the business"]', '[{"section":"1798.140(ag)(1)","description":"Definition of service provider"},{"section":"1798.140(ag)(2)","description":"Written contract requirements"},{"section":"1798.140(ag)(3)","description":"Prohibition on selling/sharing received PI"},{"section":"1798.140(ag)(4)","description":"Prohibition on combining PI from multiple sources"}]', '["service_provider_agreement","data_processing_addendum","vendor_assessment","CCPA_compliance_certification","PI_flow_map"]', '["privacy-data-protection-audit"]', 'California Attorney General / California Privacy Protection Agency', 0, 1, datetime('now'), datetime('now'));

-- CCPA Private Right of Action — Data Breach (CC §1798.150)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_016', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.150', 'CC § 1798.150', 'CCPA Private Right of Action for Data Breaches', 'Any consumer whose nonencrypted and nonredacted personal information is subject to an unauthorized access and exfiltration, theft, or disclosure as a result of the business''s violation of the duty to implement and maintain reasonable security procedures and practices may institute a civil action. Statutory damages range from $100 to $750 per consumer per incident, or actual damages, whichever is greater. This is the only section of the CCPA that provides a private right of action. The consumer must provide 30 days written notice to the business before filing suit, allowing the business to cure the violation.', '["Private right of action for data breaches only","Applies to nonencrypted and nonredacted PI","Business must have failed to maintain reasonable security","Statutory damages: $100-$750 per consumer per incident","Or actual damages, whichever is greater","30-day notice and cure period required before filing","Court may award injunctive or declaratory relief","Class action suits permitted under this section"]', '[{"section":"1798.150(a)(1)","description":"Private right of action for unauthorized access/disclosure"},{"section":"1798.150(a)(2)","description":"Damages: statutory $100-$750 or actual"},{"section":"1798.150(b)","description":"30-day notice and cure period"},{"section":"1798.150(c)","description":"Attorney General notification requirement for class actions"}]', '["breach_notification","incident_response_plan","security_assessment","30_day_cure_notice","class_action_complaint","data_breach_report"]', '["privacy-data-protection-audit"]', 'California Superior Courts / California Attorney General', 1, 1, datetime('now'), datetime('now'));


