-- HIPAA Privacy Rule (45 CFR Part 160, 164 Subpart E)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_017', 'PRIVAXIS', 'FEDERAL_REGULATION', 'US', '45 CFR Part 160; 45 CFR Part 164, Subpart E', '45 CFR §§ 164.500-534', 'HIPAA Privacy Rule — Standards for Protection of Individually Identifiable Health Information', 'The HIPAA Privacy Rule establishes national standards to protect individuals'' medical records and other individually identifiable health information (protected health information, or PHI). It applies to health plans, health care clearinghouses, and health care providers who conduct standard electronic transactions (covered entities), as well as their business associates. The rule requires appropriate safeguards to protect the privacy of PHI, sets limits on the uses and disclosures that may be made of such information without individual authorization, and gives individuals rights over their health information.', '["Designate a Privacy Officer responsible for compliance","Develop and implement written privacy policies and procedures","Provide Notice of Privacy Practices to all patients","Obtain individual authorization for uses/disclosures not permitted or required","Apply minimum necessary standard to uses and disclosures","Train all workforce members on privacy policies","Implement administrative, technical, and physical safeguards","Maintain documentation of compliance efforts for six years","Establish complaint process for privacy violations","Conduct risk assessments of privacy practices"]', '[{"section":"164.502","description":"Uses and disclosures of PHI — general rules"},{"section":"164.508","description":"Uses and disclosures for which authorization is required"},{"section":"164.510","description":"Uses and disclosures requiring opportunity to agree or object"},{"section":"164.512","description":"Uses and disclosures for which consent/authorization not required"},{"section":"164.520","description":"Notice of Privacy Practices"},{"section":"164.530","description":"Administrative requirements — policies, training, safeguards"}]', '["Notice_of_Privacy_Practices","authorization_form","privacy_policy","workforce_training_record","risk_assessment","complaint_log","BAA"]', '["privacy-data-protection-audit"]', 'HHS Office for Civil Rights (OCR)', 0, 1, datetime('now'), datetime('now'));

-- HIPAA Security Rule (45 CFR Part 164 Subpart C)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_018', 'PRIVAXIS', 'FEDERAL_REGULATION', 'US', '45 CFR Part 164, Subpart C', '45 CFR §§ 164.302-318', 'HIPAA Security Rule — Standards for Protection of Electronic PHI', 'The HIPAA Security Rule establishes national standards to protect electronic protected health information (ePHI) that is created, received, used, or maintained by a covered entity or business associate. It requires appropriate administrative, physical, and technical safeguards to ensure the confidentiality, integrity, and availability of ePHI. The rule is flexible and scalable, allowing covered entities to adopt measures appropriate to their size, complexity, and capabilities. Standards are designated as either "required" or "addressable" implementation specifications.', '["Conduct thorough risk analysis of ePHI vulnerabilities","Implement risk management program to reduce identified risks","Designate a Security Officer responsible for compliance","Implement workforce security — authorization and access controls","Implement security awareness and training program","Establish contingency plan: data backup, disaster recovery, emergency operations","Implement audit controls to record and examine ePHI access","Implement access controls: unique user identification, encryption, auto-logoff","Implement transmission security: integrity controls and encryption","Implement facility access controls and workstation security"]', '[{"section":"164.308","description":"Administrative safeguards — risk analysis, management, training"},{"section":"164.310","description":"Physical safeguards — facility access, workstation, device security"},{"section":"164.312","description":"Technical safeguards — access controls, audit, integrity, transmission"},{"section":"164.314","description":"Organizational requirements — BAAs and group health plans"},{"section":"164.316","description":"Documentation requirements — policies, procedures, retention"}]', '["risk_analysis","security_policy","contingency_plan","audit_log","access_control_policy","encryption_policy","BAA","workforce_training_record","incident_response_plan"]', '["privacy-data-protection-audit"]', 'HHS Office for Civil Rights (OCR)', 0, 1, datetime('now'), datetime('now'));

-- HIPAA Breach Notification Rule (45 CFR §§ 164.400-414)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_019', 'PRIVAXIS', 'FEDERAL_REGULATION', 'US', '45 CFR §§ 164.400-414', '45 CFR §§ 164.400-414', 'HIPAA Breach Notification Rule', 'The Breach Notification Rule requires HIPAA covered entities and their business associates to provide notification following a breach of unsecured protected health information. A breach is defined as an impermissible use or disclosure under the Privacy Rule that compromises the security or privacy of PHI. An exception exists where a covered entity or business associate demonstrates a low probability that the PHI has been compromised based on a four-factor risk assessment. Individual notifications must be provided without unreasonable delay and no later than 60 calendar days from discovery of the breach.', '["Notify affected individuals within 60 days of breach discovery","Notify HHS Secretary — immediately if 500+ individuals affected","Notify HHS Secretary annually if fewer than 500 affected","Notify prominent media outlets if 500+ individuals in a state affected","Conduct four-factor risk assessment to determine if breach occurred","Business associates must notify covered entities within 60 days","Individual notice must be written and sent by first-class mail","Substitute notice permitted when contact information is insufficient","Maintain breach log for incidents affecting fewer than 500 individuals"]', '[{"section":"164.400","description":"Applicability of breach notification requirements"},{"section":"164.402","description":"Definition of breach and exceptions"},{"section":"164.404","description":"Notification to individuals"},{"section":"164.406","description":"Notification to media for breaches affecting 500+"},{"section":"164.408","description":"Notification to HHS Secretary"},{"section":"164.410","description":"Business associate notification to covered entity"},{"section":"164.414","description":"Administrative requirements and burden of proof"}]', '["breach_notification_letter","HHS_breach_report","risk_assessment","breach_log","media_notification","incident_response_report"]', '["privacy-data-protection-audit"]', 'HHS Office for Civil Rights (OCR)', 0, 1, datetime('now'), datetime('now'));

-- HIPAA Right of Access (45 CFR § 164.524)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_020', 'PRIVAXIS', 'FEDERAL_REGULATION', 'US', '45 CFR § 164.524', '45 CFR § 164.524', 'HIPAA Individual Right of Access to Protected Health Information', 'Individuals have the right to inspect and obtain a copy of their protected health information in a designated record set maintained by or for a covered entity. The covered entity must act on a request within 30 days (one 30-day extension permitted). The copy must be provided in the form and format requested if readily producible, or in a readable hard copy. Fees must be limited to reasonable, cost-based amounts for labor, supplies, and postage. HHS OCR has made enforcement of the Right of Access a priority through its Right of Access Initiative, resulting in numerous settlements.', '["Provide access to PHI within 30 days of request","One 30-day extension permitted with written notice","Provide PHI in form and format requested if readily producible","Fees limited to reasonable cost-based amounts","May not charge for search and retrieval time","Must provide copy to designated third party if requested","Only limited grounds for denial exist","Must provide written denial with basis and appeal rights","Maintain documentation of requests and responses"]', '[{"section":"164.524(a)","description":"Right of access — scope and exceptions"},{"section":"164.524(b)","description":"Requirements for request and timely action"},{"section":"164.524(c)","description":"Provision of access — form, format, fees"},{"section":"164.524(d)","description":"Grounds for denial — reviewable and unreviewable"},{"section":"164.524(e)","description":"Documentation requirements"}]', '["medical_records_request","access_denial_letter","fee_schedule","PHI_release_form","third_party_designation","appeal_record"]', '["privacy-data-protection-audit"]', 'HHS Office for Civil Rights (OCR)', 0, 1, datetime('now'), datetime('now'));

-- HIPAA Minimum Necessary Standard (45 CFR § 164.502(b))
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_021', 'PRIVAXIS', 'FEDERAL_REGULATION', 'US', '45 CFR § 164.502(b); 45 CFR § 164.514(d)', '45 CFR § 164.502(b)', 'HIPAA Minimum Necessary Standard', 'When using or disclosing protected health information or when requesting PHI from another covered entity or business associate, a covered entity must make reasonable efforts to limit PHI to the minimum necessary to accomplish the intended purpose. This principle does not apply to disclosures to or requests by a health care provider for treatment, disclosures to the individual who is the subject of the information, uses or disclosures pursuant to an individual''s authorization, disclosures to HHS for compliance investigations, or uses or disclosures required by law.', '["Limit PHI uses and disclosures to minimum necessary","Identify workforce members needing access and categories of PHI needed","Implement policies for routine and non-routine disclosures","For routine requests, limit to reasonably necessary categories","For non-routine requests, review individually on case-by-case basis","Does not apply to treatment disclosures between providers","Does not apply to disclosures to the individual subject","Does not apply to uses pursuant to individual authorization","Reasonable reliance on requesting party is permitted"]', '[{"section":"164.502(b)(1)","description":"Minimum necessary standard for uses"},{"section":"164.502(b)(2)","description":"Minimum necessary standard for disclosures and requests"},{"section":"164.514(d)(1)","description":"Minimum necessary — uses by covered entity"},{"section":"164.514(d)(2)","description":"Minimum necessary — routine disclosures"},{"section":"164.514(d)(3)","description":"Minimum necessary — non-routine disclosures"},{"section":"164.514(d)(4)","description":"Minimum necessary — requests for PHI"},{"section":"164.514(d)(5)","description":"Reasonable reliance exception"}]', '["role_based_access_policy","PHI_access_matrix","disclosure_log","workforce_access_roster","minimum_necessary_policy"]', '["privacy-data-protection-audit"]', 'HHS Office for Civil Rights (OCR)', 0, 1, datetime('now'), datetime('now'));

-- HIPAA Business Associate Requirements (45 CFR § 164.502(e))
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_022', 'PRIVAXIS', 'FEDERAL_REGULATION', 'US', '45 CFR § 164.502(e); 45 CFR § 164.504(e)', '45 CFR § 164.502(e)', 'HIPAA Business Associate Agreement Requirements', 'A covered entity may disclose PHI to a business associate and may allow a business associate to create, receive, maintain, or transmit PHI on its behalf only if the covered entity obtains satisfactory assurances through a written Business Associate Agreement (BAA). The BAA must establish the permitted and required uses and disclosures of PHI, require the BA to implement appropriate safeguards, require reporting of breaches and security incidents, and ensure that subcontractors agree to the same restrictions. Since the HITECH Act, business associates are directly liable for HIPAA compliance.', '["Execute written Business Associate Agreement before sharing PHI","BAA must specify permitted uses and disclosures of PHI","BAA must require appropriate safeguards for PHI","BAA must require BA to report breaches and security incidents","BAA must require BA to ensure subcontractors comply","BAA must require BA to make PHI available for individual access rights","BAA must require return or destruction of PHI upon termination","Covered entity must take action upon knowledge of BA violation","Business associates directly liable under HITECH Act","Maintain inventory of all business associate relationships"]', '[{"section":"164.502(e)(1)","description":"Requirement for business associate agreement"},{"section":"164.502(e)(2)","description":"Exception — not required when disclosure is to provider for treatment"},{"section":"164.504(e)(1)","description":"BAA required before any disclosure to BA"},{"section":"164.504(e)(2)","description":"Required provisions of BAA"},{"section":"164.504(e)(3)","description":"Covered entity obligations regarding BA compliance"},{"section":"164.504(e)(4)","description":"Termination and cure provisions"}]', '["BAA","vendor_inventory","subcontractor_agreement","breach_reporting_protocol","PHI_flow_map","BA_compliance_assessment"]', '["privacy-data-protection-audit"]', 'HHS Office for Civil Rights (OCR)', 0, 1, datetime('now'), datetime('now'));


