-- TCPA Autodialer Restrictions (47 USC § 227(b))
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_023', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '47 USC § 227(b)', '47 USC § 227(b)', 'TCPA Restrictions on Use of Automatic Telephone Dialing Systems and Prerecorded Messages', 'The Telephone Consumer Protection Act prohibits making calls using an automatic telephone dialing system (ATDS) or an artificial or prerecorded voice to wireless telephone numbers, emergency lines, hospital patient rooms, and similar services without prior express consent. Following the Supreme Court''s decision in Facebook v. Duguid (2021), an ATDS is defined as equipment with the capacity to store or produce telephone numbers using a random or sequential number generator and to dial such numbers. Prior express written consent is required for telemarketing calls; prior express consent is required for non-marketing calls.', '["No ATDS calls to wireless numbers without prior express consent","Prior express written consent required for telemarketing via ATDS","No prerecorded/artificial voice calls to residential lines without consent","No calls to emergency lines (911), hospital rooms, or similar services","Caller must provide automated opt-out mechanism during prerecorded calls","Opt-out must be available throughout the duration of the call","ATDS defined per Facebook v. Duguid: random/sequential number generator","Exemptions for emergency calls and calls with prior express consent","Must honor revocation of consent by any reasonable means"]', '[{"section":"227(b)(1)(A)","description":"Prohibition on ATDS/prerecorded calls to emergency lines"},{"section":"227(b)(1)(B)","description":"Prohibition on prerecorded calls to residential lines"},{"section":"227(b)(1)(C)","description":"Prohibition on ATDS calls to cell phones without consent"},{"section":"227(b)(2)","description":"FCC authority to exempt certain calls"},{"section":"227(b)(3)","description":"Private right of action — $500 per violation, trebled for willful"}]', '["consent_record","ATDS_compliance_policy","call_log","opt_out_record","written_consent_form","telemarketing_script"]', '["privacy-data-protection-audit"]', 'Federal Communications Commission (FCC)', 1, 1, datetime('now'), datetime('now'));

-- TCPA Do-Not-Call Provisions (47 USC § 227(c))
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_024', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '47 USC § 227(c)', '47 USC § 227(c)', 'TCPA Do-Not-Call Registry and Company-Specific Do-Not-Call Lists', 'The TCPA requires the FCC to establish regulations for protecting residential telephone subscribers'' privacy rights, including a national Do-Not-Call (DNC) registry. Telemarketers must scrub their call lists against the National Do-Not-Call Registry maintained by the FTC. Companies must also maintain their own internal do-not-call lists of consumers who request not to be called. The company-specific DNC list must be honored for five years. Violations may be enforced by state attorneys general and through private right of action for actual monetary loss or $500 per violation.', '["Scrub call lists against National DNC Registry before calling","Maintain company-specific do-not-call list","Honor company-specific DNC requests for five years","Process DNC requests within 30 days","Train personnel engaged in telephone solicitation on DNC procedures","Maintain written DNC compliance procedures","Identify seller and purpose at beginning of each call","Provide telephone number or address for DNC requests","Update National DNC Registry data at least every 31 days"]', '[{"section":"227(c)(1)","description":"FCC authority to establish DNC regulations"},{"section":"227(c)(2)","description":"Company-specific do-not-call requirements"},{"section":"227(c)(3)","description":"National Do-Not-Call Registry regulations"},{"section":"227(c)(5)","description":"Private right of action — $500 per violation"}]', '["DNC_compliance_policy","call_list_scrub_record","internal_DNC_list","training_record","telemarketing_script","DNC_request_log"]', '["privacy-data-protection-audit"]', 'Federal Communications Commission (FCC) / Federal Trade Commission (FTC)', 1, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- PRIVAXIS — Other Federal Privacy
-- ═══════════════════════════════════════════════════════════════════════════

-- FERPA — Education Records Privacy (20 USC § 1232g)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_025', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '20 USC § 1232g', '20 USC § 1232g', 'Family Educational Rights and Privacy Act (FERPA)', 'FERPA protects the privacy of student education records. It applies to all educational agencies and institutions that receive funds under any program administered by the U.S. Department of Education. FERPA gives parents rights to access their children''s education records, request corrections, and control disclosures. These rights transfer to the student upon reaching 18 years of age or attending a postsecondary institution (eligible student). Schools must have written permission from the parent or eligible student before releasing any information from a student''s education record, subject to enumerated exceptions.', '["Annual notification of rights to parents and eligible students","Allow inspection and review of education records within 45 days","Provide opportunity to request amendment of inaccurate records","Obtain written consent before disclosing personally identifiable information","Maintain record of each disclosure request and to whom disclosed","Directory information may be disclosed only with proper notice and opt-out","FERPA exceptions: school officials with legitimate educational interest","FERPA exceptions: transfer schools, financial aid, accreditation, health/safety","Must comply to maintain eligibility for federal education funding"]', '[{"section":"1232g(a)(1)","description":"Right to inspect and review education records"},{"section":"1232g(a)(2)","description":"Right to request amendment and hearing"},{"section":"1232g(b)(1)","description":"Prohibition on disclosure without consent"},{"section":"1232g(b)(1)(A-J)","description":"Exceptions to consent requirement"},{"section":"1232g(b)(2)","description":"Disclosure requirements and recordkeeping"},{"section":"1232g(d)","description":"Student access rights at postsecondary institutions"}]', '["annual_FERPA_notice","consent_to_release_form","education_record","disclosure_log","directory_information_notice","opt_out_form","amendment_request"]', '["privacy-data-protection-audit"]', 'U.S. Department of Education — Family Policy Compliance Office', 0, 1, datetime('now'), datetime('now'));

-- COPPA — Children's Online Privacy (15 USC §§ 6501-6506)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_026', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '15 USC §§ 6501-6506; 16 CFR Part 312', '15 USC §§ 6501-6506', 'Children''s Online Privacy Protection Act (COPPA)', 'COPPA imposes requirements on operators of websites and online services directed to children under 13 years of age, and on operators of other websites or online services that have actual knowledge they are collecting personal information from children under 13. Operators must provide notice of information practices, obtain verifiable parental consent before collecting personal information from children, give parents the ability to review and delete their child''s information, and maintain the confidentiality, security, and integrity of children''s personal information. The FTC Rule (16 CFR Part 312) implements the statute.', '["Post clear and comprehensive online privacy policy","Provide direct notice to parents before collection","Obtain verifiable parental consent before collecting PI from children under 13","Allow parents to review child''s personal information","Allow parents to revoke consent and require deletion","Do not condition child''s participation on disclosure of more PI than necessary","Maintain confidentiality, security, and integrity of children''s PI","Retain children''s PI only as long as reasonably necessary","Applies to actual knowledge of collection from children under 13","Safe harbor programs available through FTC-approved self-regulatory guidelines"]', '[{"section":"6502(a)","description":"Prohibition on unfair/deceptive collection from children"},{"section":"6502(b)","description":"FTC rulemaking authority and required regulations"},{"section":"6502(b)(1)(A)","description":"Notice requirements"},{"section":"6502(b)(1)(B)","description":"Verifiable parental consent"},{"section":"6502(b)(1)(C)","description":"Parental access to child''s information"},{"section":"6502(b)(1)(D)","description":"Data minimization for children''s PI"},{"section":"6505","description":"State AG enforcement authority"}]', '["children_privacy_policy","parental_consent_form","age_verification_mechanism","parental_access_request","data_retention_policy","COPPA_compliance_assessment"]', '["privacy-data-protection-audit"]', 'Federal Trade Commission (FTC)', 0, 1, datetime('now'), datetime('now'));

-- CAN-SPAM Act (15 USC §§ 7701-7713)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_027', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '15 USC §§ 7701-7713; 16 CFR Part 316', '15 USC §§ 7701-7713', 'CAN-SPAM Act — Controlling the Assault of Non-Solicited Pornography and Marketing', 'The CAN-SPAM Act establishes requirements for commercial electronic mail messages, gives recipients the right to stop receiving commercial emails, and spells out penalties for violations. It applies to all commercial messages — defined as any electronic mail message the primary purpose of which is the commercial advertisement or promotion of a commercial product or service. The Act does not require opt-in consent but mandates opt-out mechanisms. The FTC enforces the Act and has issued implementing regulations at 16 CFR Part 316. CAN-SPAM preempts state laws that regulate commercial email except for fraud and computer crime statutes.', '["Do not use false or misleading header information","Do not use deceptive subject lines","Identify the message as an advertisement","Include valid physical postal address of sender","Provide clear and conspicuous opt-out mechanism","Honor opt-out requests within 10 business days","Do not sell or transfer email addresses of opted-out recipients","Do not use harvested email addresses","Monitor compliance by third parties sending on your behalf","Each separate email in violation constitutes a separate offense"]', '[{"section":"7704(a)(1)","description":"Prohibition on false/misleading transmission information"},{"section":"7704(a)(2)","description":"Prohibition on deceptive subject headings"},{"section":"7704(a)(3)","description":"Inclusion of return address or opt-out mechanism"},{"section":"7704(a)(4)","description":"Prohibition on transmission after opt-out"},{"section":"7704(a)(5)","description":"Identification and physical address requirements"},{"section":"7704(b)","description":"Aggravated violations — harvesting, dictionary attacks, unauthorized relay"},{"section":"7706","description":"Enforcement by FTC, state AGs, and ISPs"}]', '["email_marketing_policy","opt_out_mechanism","email_compliance_checklist","suppression_list","sender_information_record","third_party_monitoring_log"]', '["privacy-data-protection-audit"]', 'Federal Trade Commission (FTC)', 0, 1, datetime('now'), datetime('now'));

-- Right to Financial Privacy Act (12 USC §§ 3401-3422)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_028', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '12 USC §§ 3401-3422', '12 USC §§ 3401-3422', 'Right to Financial Privacy Act (RFPA)', 'The Right to Financial Privacy Act protects the confidentiality of personal financial records by creating a statutory Fourth Amendment protection for bank records. It establishes procedures that federal government authorities must follow when seeking to obtain customers'' financial records from financial institutions. No government authority may have access to the financial records of any customer from a financial institution unless the records are reasonably described and obtained through one of five authorized access methods: customer authorization, administrative subpoena, search warrant, judicial subpoena, or formal written request.', '["Financial records accessible only through five authorized methods","Customer authorization must be knowing and voluntary","Customer must receive notice of government access request","Customer has right to challenge access in court within 10 days","Financial institutions must maintain records of disclosures to government","Government must certify records are relevant to legitimate law enforcement inquiry","Records must be reasonably described in the access request","Customer may authorize access — must be signed and dated","Financial institution may challenge if request is unduly burdensome"]', '[{"section":"3402","description":"Access only through authorized procedures"},{"section":"3403","description":"Confidentiality and prohibition on disclosure"},{"section":"3404","description":"Customer authorization requirements"},{"section":"3405","description":"Administrative subpoena and summons"},{"section":"3406","description":"Search warrant requirements"},{"section":"3407","description":"Judicial subpoena requirements"},{"section":"3408","description":"Formal written request requirements"},{"section":"3410","description":"Customer challenge procedures"},{"section":"3417","description":"Civil penalties for violations"}]', '["customer_authorization","government_access_request","financial_records_subpoena","customer_notice","challenge_motion","disclosure_log"]', '["privacy-data-protection-audit"]', 'U.S. Department of the Treasury / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Cable Communications Privacy Act (47 USC § 551)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_029', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '47 USC § 551', '47 USC § 551', 'Cable Communications Policy Act — Subscriber Privacy Protections', 'Section 551 of the Cable Communications Policy Act of 1984 governs the collection and disclosure of personally identifiable information by cable operators. Cable operators must provide subscribers with a notice of privacy practices at the time of entering into a service agreement and at least once annually thereafter. Cable operators may not collect personally identifiable information without prior written or electronic consent except as necessary to render service or detect unauthorized reception. Subscribers have the right to access and correct their personally identifiable information. Statutory damages of not less than $1,000 or actual damages, whichever is greater.', '["Provide written privacy notice at subscription and annually","Obtain prior consent before collecting PI beyond service necessity","Do not disclose PI without subscriber consent or court order","Destroy PI when no longer necessary for collected purpose","Allow subscriber access to their PI within 30 days","Allow subscriber to correct inaccurate PI","Government access requires court order with clear and convincing evidence","Maintain only PI necessary for legitimate business activity"]', '[{"section":"551(a)","description":"Privacy notice requirements — at subscription and annually"},{"section":"551(b)","description":"Limitations on collection of PI"},{"section":"551(c)","description":"Limitations on disclosure of PI"},{"section":"551(d)","description":"Subscriber access to PI"},{"section":"551(e)","description":"Destruction of PI when no longer needed"},{"section":"551(f)","description":"Civil action — $1,000 statutory damages minimum"},{"section":"551(h)","description":"Government access — court order requirement"}]', '["privacy_notice","subscriber_consent_form","PI_collection_policy","subscriber_access_request","data_destruction_record","court_order"]', '["privacy-data-protection-audit"]', 'Federal Communications Commission (FCC) / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Video Privacy Protection Act (18 USC § 2710)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_030', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '18 USC § 2710', '18 USC § 2710', 'Video Privacy Protection Act (VPPA)', 'The VPPA prohibits a video tape service provider from knowingly disclosing personally identifiable information concerning any consumer of the provider without the consumer''s informed, written consent. Enacted in response to the disclosure of Judge Robert Bork''s video rental records during his Supreme Court confirmation hearings. The Act applies to any person engaged in the business of rental, sale, or delivery of prerecorded video cassette tapes or similar audio visual materials, which courts have extended to cover streaming services. Provides for actual damages of not less than $2,500, punitive damages, attorneys'' fees, and equitable relief.', '["Do not disclose PI of consumers without informed written consent","Consent must be separate and distinct from any other legal agreement","Consent may be given electronically per 2012 amendment","Destroy PI within one year after it is no longer necessary","PI includes information identifying a person as having requested specific materials","Law enforcement access requires warrant, court order, or grand jury subpoena","Actual damages minimum $2,500 per violation","Punitive damages available","Attorneys'' fees and costs recoverable"]', '[{"section":"2710(a)","description":"Definitions — video tape service provider, consumer, PI"},{"section":"2710(b)(1)","description":"Prohibition on disclosure without consent"},{"section":"2710(b)(2)","description":"Permitted disclosures — consent, law enforcement, court order"},{"section":"2710(c)","description":"Civil action — $2,500 minimum, punitive damages, attorneys'' fees"},{"section":"2710(e)","description":"Destruction requirement — one year after no longer necessary"}]', '["consumer_consent_form","video_rental_records","disclosure_log","data_destruction_record","law_enforcement_request","privacy_policy"]', '["privacy-data-protection-audit"]', 'Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Driver's Privacy Protection Act (18 USC §§ 2721-2725)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_031', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '18 USC §§ 2721-2725', '18 USC §§ 2721-2725', 'Driver''s Privacy Protection Act (DPPA)', 'The DPPA prohibits the knowing disclosure or use of personal information obtained from state motor vehicle records for any purpose not permitted by the Act. Enacted in 1994 after the murder of actress Rebecca Schaeffer, whose address was obtained from California DMV records. The Act restricts state DMVs and their officers, employees, and contractors from disclosing personal information from motor vehicle records. Fourteen enumerated permissible uses exist, including use by government agencies, motor vehicle safety, licensed private investigators, and with the express consent of the person. Liquidated damages of not less than $2,500 per violation.', '["State DMVs may not disclose personal information from motor vehicle records","Fourteen enumerated permissible uses for disclosure","Express consent of the individual is a permissible use","Resale or redisclosure must be for permitted purposes only","Criminal penalties: fines for knowing violations","Civil action: liquidated damages not less than $2,500 per violation","Punitive damages and attorneys'' fees available","State and federal officials subject to Act","Motor vehicle records include name, address, phone, SSN, DL number, photo"]', '[{"section":"2721(a)","description":"Prohibition on disclosure of PI from motor vehicle records"},{"section":"2721(b)","description":"Fourteen permissible uses for disclosure"},{"section":"2722","description":"Additional unlawful acts — false representation to obtain records"},{"section":"2723","description":"Criminal fine for knowing violations"},{"section":"2724","description":"Civil action — $2,500 liquidated damages, punitive, attorneys'' fees"},{"section":"2725","description":"Definitions — motor vehicle record, personal information"}]', '["DMV_records_request","consent_form","permissible_use_certification","disclosure_log","motor_vehicle_record","privacy_policy"]', '["privacy-data-protection-audit"]', 'U.S. Department of Justice / Federal Courts', 1, 1, datetime('now'), datetime('now'));

-- Gramm-Leach-Bliley Privacy Provisions (15 USC §§ 6801-6809)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_032', 'PRIVAXIS', 'FEDERAL_STATUTE', 'US', '15 USC §§ 6801-6809; 16 CFR Part 314', '15 USC §§ 6801-6809', 'Gramm-Leach-Bliley Act — Financial Privacy Provisions', 'Title V of the Gramm-Leach-Bliley Act (GLB Act) requires financial institutions to explain their information-sharing practices to customers and to safeguard sensitive data. The Financial Privacy Rule (Regulation P, 12 CFR Part 1016) governs the collection and disclosure of customers'' personal financial information by financial institutions. The Safeguards Rule (16 CFR Part 314, updated 2023) requires financial institutions to develop, implement, and maintain a comprehensive information security program. Financial institutions must provide initial and annual privacy notices and allow customers to opt out of sharing nonpublic personal information with nonaffiliated third parties.', '["Provide initial privacy notice at customer relationship establishment","Provide annual privacy notice to customers","Allow opt-out of sharing NPI with nonaffiliated third parties","Do not disclose account numbers to nonaffiliated third parties for marketing","Develop comprehensive written information security program","Designate qualified individual to oversee security program","Conduct risk assessments of customer information","Implement safeguards to control identified risks","Regularly test and monitor effectiveness of safeguards","Oversee service providers by requiring contractual security obligations","Maintain incident response plan"]', '[{"section":"6801","description":"Protection of nonpublic personal information — policy declaration"},{"section":"6802","description":"Obligations with respect to disclosures of personal information"},{"section":"6803","description":"Disclosure of institution privacy policy — initial and annual"},{"section":"6804","description":"Rulemaking authority — functional regulators"},{"section":"6805","description":"Enforcement — federal banking agencies, SEC, FTC, state insurance"},{"section":"6809","description":"Definitions — financial institution, nonpublic personal information"}]', '["privacy_notice","opt_out_form","information_security_program","risk_assessment","safeguards_policy","vendor_oversight_record","incident_response_plan","annual_privacy_notice"]', '["privacy-data-protection-audit"]', 'FTC / Federal Banking Agencies / SEC / State Insurance Authorities', 0, 1, datetime('now'), datetime('now'));


-- ═══════════════════════════════════════════════════════════════════════════
-- PRIVAXIS — California State Privacy
-- ═══════════════════════════════════════════════════════════════════════════

-- CalOPPA — Online Privacy Protection (BPC §§ 22575-22579)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_033', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 22575-22579', 'BPC §§ 22575-22579', 'California Online Privacy Protection Act (CalOPPA)', 'CalOPPA was the first state law in the nation to require commercial websites and online services to conspicuously post a privacy policy. It applies to any operator of a commercial website or online service that collects personally identifiable information through the internet about individual consumers residing in California who use or visit the commercial website or online service. The law requires the privacy policy to identify the categories of PII collected, categories of third parties with whom information may be shared, the process for reviewing and requesting changes to PII, how the operator notifies consumers of material changes, and the effective date of the policy.', '["Conspicuously post privacy policy on website or online service","Identify categories of PII collected","Identify categories of third parties with whom PII may be shared","Describe process for consumer to review and request changes to PII","Describe how operator notifies consumers of material policy changes","Include effective date of the privacy policy","Disclose how operator responds to Do Not Track signals","Disclose whether third parties may collect PII across sites","Must comply within 30 days of being notified of noncompliance"]', '[{"section":"22575(a)","description":"Conspicuous posting requirement"},{"section":"22575(b)","description":"Required content of privacy policy"},{"section":"22575(b)(5)","description":"Effective date requirement"},{"section":"22575(b)(6)","description":"Do Not Track disclosure"},{"section":"22575(b)(7)","description":"Third-party tracking disclosure"},{"section":"22577","description":"Definitions — operator, PII, conspicuously post"}]', '["privacy_policy","website_compliance_audit","DNT_disclosure","PII_inventory","privacy_policy_changelog"]', '["privacy-data-protection-audit"]', 'California Attorney General', 0, 1, datetime('now'), datetime('now'));

-- CA Data Breach Notification (CC § 1798.82)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_034', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code § 1798.82', 'CC § 1798.82', 'California Data Breach Notification Law', 'California''s data breach notification statute requires any person or business that conducts business in California, and that owns or licenses computerized data that includes personal information, to disclose a breach of the security of the system to any resident of California whose unencrypted personal information was, or is reasonably believed to have been, acquired by an unauthorized person. Notification must be made in the most expedient time possible and without unreasonable delay. Personal information includes name plus SSN, DL number, financial account numbers, medical information, health insurance information, or biometric data. Notification must be in a specific format prescribed by statute.', '["Notify affected California residents of breach in most expedient time possible","Notification without unreasonable delay","Must use prescribed statutory format for notification","Include name and contact information of notifying entity","Describe types of PI subject to breach","General description of the breach incident","Date or estimated date of breach","Toll-free telephone numbers of major credit reporting agencies if SSN/DL","If 500+ residents affected, submit sample notification to Attorney General","Encryption is a safe harbor — encrypted data not covered"]', '[{"section":"1798.82(a)","description":"Notification obligation and timing"},{"section":"1798.82(b)","description":"Methods of notification — written, electronic, substitute"},{"section":"1798.82(d)","description":"Required content of notification"},{"section":"1798.82(e)","description":"Definition of personal information"},{"section":"1798.82(f)","description":"AG notification if 500+ affected"},{"section":"1798.82(g)","description":"Encryption safe harbor"}]', '["breach_notification_letter","AG_notification","incident_response_plan","breach_assessment","credit_monitoring_offer","data_inventory"]', '["privacy-data-protection-audit"]', 'California Attorney General', 0, 1, datetime('now'), datetime('now'));

-- CA Constitutional Right to Privacy (Art. I, § 1)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_035', 'PRIVAXIS', 'CONSTITUTIONAL', 'CA', 'Cal. Const., Art. I, § 1', 'Art. I, § 1', 'California Constitutional Right to Privacy', 'Article I, Section 1 of the California Constitution enumerates privacy as an inalienable right alongside life, liberty, and the pursuit of happiness. Added by voter initiative (Proposition 11) in 1972, it was intended to constrain both government and private entities. Unlike the federal constitutional right to privacy, California''s constitutional privacy right applies to private actors as well as state actors. Under Hill v. National Collegiate Athletic Assn. (1994) 7 Cal.4th 1, a plaintiff must establish: (1) a legally protected privacy interest, (2) a reasonable expectation of privacy, and (3) a serious invasion of privacy. The defendant may assert the invasion was justified by a competing interest.', '["Privacy is an inalienable right under California Constitution","Applies to both government AND private actors","Three-part test from Hill v. NCAA: legally protected interest, reasonable expectation, serious invasion","Defendant may justify invasion with competing interest","Covers informational privacy — control of personal information","Covers autonomy privacy — freedom to make personal decisions","Applies to employment, medical records, financial information, surveillance","Broader protection than federal Fourth Amendment","Ballot argument: prevent government and business snooping"]', '[{"section":"Art. I, § 1","description":"All people have inalienable rights including privacy"},{"section":"Hill v. NCAA (1994)","description":"Three-part test for privacy claims against private actors"},{"section":"Prop. 11 (1972)","description":"Voter initiative adding privacy as inalienable right"}]', '["privacy_impact_assessment","constitutional_challenge","privacy_complaint","surveillance_policy","employee_monitoring_policy","data_collection_notice"]', '["privacy-data-protection-audit"]', 'California Courts', 1, 1, datetime('now'), datetime('now'));

-- Confidentiality of Medical Information Act (CC §§ 56-56.37)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_036', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Civ. Code §§ 56-56.37', 'CC §§ 56-56.37', 'Confidentiality of Medical Information Act (CMIA)', 'The California Confidentiality of Medical Information Act (CMIA) restricts the disclosure of medical information by health care providers, health care service plans (insurers), and contractors. It provides protections that in many respects exceed HIPAA. The CMIA prohibits any provider of health care, health care service plan, or contractor from disclosing medical information regarding a patient without first obtaining an authorization from the patient, except as specified. Authorizations must be handwritten by the patient or in a typeface no smaller than 14-point type. Negligent release results in $1,000 nominal damages; willful violation results in $5,000 plus actual damages and attorneys'' fees.', '["Do not disclose medical information without patient authorization","Authorization must be handwritten or 14-point type minimum","Authorization must specify who may disclose, what may be disclosed, and to whom","Employer must establish procedure to preserve confidentiality","Employer cannot use medical information for employment discrimination","Medical information includes mental health and substance abuse records","Patient may revoke authorization at any time","$1,000 nominal damages for negligent release","$5,000 per violation plus actual damages for willful disclosure","Applies to providers, plans, contractors, and employers"]', '[{"section":"56.10","description":"Prohibition on disclosure without authorization"},{"section":"56.11","description":"Authorization requirements — form and content"},{"section":"56.13","description":"Employer confidentiality requirements"},{"section":"56.20","description":"Provider obligation to preserve confidentiality"},{"section":"56.26","description":"Pharmaceutical company restrictions"},{"section":"56.35","description":"Negligent disclosure — $1,000 nominal damages"},{"section":"56.36","description":"Willful disclosure — $5,000 plus actual damages and fees"}]', '["patient_authorization_form","medical_information_policy","employer_confidentiality_policy","breach_report","CMIA_compliance_audit","disclosure_log"]', '["privacy-data-protection-audit"]', 'California Courts / California Department of Managed Health Care', 1, 1, datetime('now'), datetime('now'));

-- CA Invasion of Privacy Act (PC §§ 630-638)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_037', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Penal Code §§ 630-638', 'PC §§ 630-638', 'California Invasion of Privacy Act (CIPA) — Wiretapping and Electronic Surveillance', 'The California Invasion of Privacy Act is one of the strongest electronic surveillance protection statutes in the nation. California is a "two-party consent" state — all parties to a confidential communication must consent to its recording. Section 631 prohibits wiretapping or intentionally recording confidential telephone communications without the consent of all parties. Section 632 prohibits eavesdropping or recording confidential communications by any means without consent of all parties. Violations are punishable as misdemeanors and carry a private right of action for the greater of $5,000 per violation or three times actual damages.', '["All-party consent required for recording confidential communications","No wiretapping of telephone or telegraph communications (§ 631)","No eavesdropping or recording without all-party consent (§ 632)","No interception of cellular/cordless telephone communications (§ 632.5)","No recording of telephone communications without beep tone warning (§ 632.7)","No intentional recording of confidential communications by eavesdropping device","Criminal penalties: fine up to $2,500 and/or one year imprisonment","Civil damages: $5,000 per violation or three times actual damages","Evidence obtained in violation is inadmissible","Exemptions for law enforcement with court order"]', '[{"section":"630","description":"Legislative declaration — right to privacy in communications"},{"section":"631","description":"Wiretapping prohibition — telephone/telegraph"},{"section":"632","description":"Eavesdropping on or recording confidential communications"},{"section":"632.5","description":"Cellular and cordless telephone communications"},{"section":"632.7","description":"Recording telephone communications without all parties'' consent"},{"section":"635","description":"Criminal penalties — misdemeanor"},{"section":"637.2","description":"Civil action — $5,000 or treble damages"}]', '["call_recording_policy","consent_notice","wiretap_order","surveillance_policy","communication_monitoring_policy","employee_notice"]', '["privacy-data-protection-audit"]', 'California District Attorneys / California Courts', 1, 1, datetime('now'), datetime('now'));

-- Student Online Personal Information Protection Act (BPC § 22584)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_038', 'PRIVAXIS', 'STATE_STATUTE', 'CA', 'Cal. Bus. & Prof. Code §§ 22584-22584.5', 'BPC § 22584', 'Student Online Personal Information Protection Act (SOPIPA)', 'SOPIPA prohibits operators of websites, online services, online applications, or mobile applications designed and marketed for K-12 school purposes from using student information for non-educational purposes. The Act was the first of its kind in the nation and has served as a model for similar legislation in other states. Operators may not use covered information for targeted advertising directed to students, build advertising profiles, sell student information, or disclose covered information except for legitimate school purposes. The operator must implement and maintain reasonable security procedures and delete covered information upon request from the school or district.', '["Do not use covered information for targeted advertising to K-12 students","Do not build advertising profiles on K-12 students","Do not sell K-12 student information","Do not disclose covered information except for school purposes","Implement and maintain reasonable security procedures","Delete covered information upon school/district request","Do not use covered information to amass non-educational profiles","Allow school/district to access and correct student information","Security practices must protect against unauthorized access","Transparency about data collection and use practices"]', '[{"section":"22584(a)","description":"Prohibition on targeted advertising to students"},{"section":"22584(b)","description":"Prohibition on building advertising profiles"},{"section":"22584(c)","description":"Prohibition on selling student information"},{"section":"22584(d)","description":"Prohibition on unauthorized disclosure"},{"section":"22584(e)","description":"Requirement for reasonable security procedures"},{"section":"22584(f)","description":"Deletion upon school/district request"},{"section":"22584.5","description":"Permitted uses and disclosures"}]', '["student_data_policy","vendor_agreement","data_deletion_request","security_assessment","school_data_inventory","SOPIPA_compliance_certification"]', '["privacy-data-protection-audit"]', 'California Attorney General', 0, 1, datetime('now'), datetime('now'));


