-- GDPR Right to Erasure (Art. 17)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_039', 'PRIVAXIS', 'INTERNATIONAL', 'EU', 'Regulation (EU) 2016/679, Article 17', 'GDPR Art. 17', 'GDPR Right to Erasure ("Right to Be Forgotten")', 'Article 17 of the General Data Protection Regulation grants data subjects the right to obtain from the controller the erasure of personal data concerning them without undue delay. The controller must erase the data where: the data is no longer necessary for its original purpose, the data subject withdraws consent and there is no other legal ground, the data subject objects under Art. 21 and there are no overriding legitimate grounds, the data has been unlawfully processed, or erasure is required to comply with a legal obligation. Where the controller has made the data public, it must take reasonable steps to inform other controllers processing the data that the data subject has requested erasure. Exceptions exist for exercising the right of freedom of expression, compliance with legal obligations, public health, archiving in the public interest, and establishment/exercise/defense of legal claims.', '["Erase personal data without undue delay upon request","Applies when data no longer necessary for original purpose","Applies when consent is withdrawn and no other legal basis exists","Applies when data subject objects and no overriding grounds exist","Applies when data was unlawfully processed","If data was made public, inform other controllers of erasure request","Take reasonable steps considering available technology and cost","Exceptions: freedom of expression, legal obligations, public health","Exceptions: archiving in public interest, scientific/historical research","Exceptions: establishment, exercise, or defense of legal claims","Respond within one month, extendable by two months for complex requests"]', '[{"section":"Art. 17(1)(a)","description":"Data no longer necessary for collection purpose"},{"section":"Art. 17(1)(b)","description":"Withdrawal of consent"},{"section":"Art. 17(1)(c)","description":"Data subject objects under Art. 21"},{"section":"Art. 17(1)(d)","description":"Unlawful processing"},{"section":"Art. 17(1)(e)","description":"Legal obligation to erase"},{"section":"Art. 17(2)","description":"Obligation to inform other controllers"},{"section":"Art. 17(3)","description":"Exceptions to right to erasure"}]', '["erasure_request","data_processing_record","consent_record","controller_notification","DPIA","privacy_policy","ROPA"]', '["privacy-data-protection-audit"]', 'EU Data Protection Authorities / European Data Protection Board', 1, 1, datetime('now'), datetime('now'));

-- GDPR Data Subject Access Rights (Art. 15)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_pri_040', 'PRIVAXIS', 'INTERNATIONAL', 'EU', 'Regulation (EU) 2016/679, Article 15', 'GDPR Art. 15', 'GDPR Right of Access by the Data Subject', 'Article 15 of the GDPR grants data subjects the right to obtain from the controller confirmation as to whether personal data concerning them is being processed, and where that is the case, access to the personal data and specified information. The controller must provide a copy of the personal data undergoing processing free of charge. For further copies, the controller may charge a reasonable fee based on administrative costs. The information must be provided in a concise, transparent, intelligible, and easily accessible form, using clear and plain language. Response must be provided without undue delay and in any event within one month, extendable by two further months where necessary given the complexity and number of requests.', '["Confirm whether personal data is being processed","Provide access to all personal data being processed","Disclose purposes of the processing","Disclose categories of personal data concerned","Disclose recipients or categories of recipients","Disclose envisaged storage period or criteria for determining period","Inform of right to rectification, erasure, restriction, and objection","Inform of right to lodge complaint with supervisory authority","Provide information on source of data if not collected from data subject","Disclose existence of automated decision-making including profiling","Provide first copy free of charge","Respond within one month, extendable by two months for complex requests","Must not adversely affect rights and freedoms of others"]', '[{"section":"Art. 15(1)(a)","description":"Purposes of the processing"},{"section":"Art. 15(1)(b)","description":"Categories of personal data"},{"section":"Art. 15(1)(c)","description":"Recipients or categories of recipients"},{"section":"Art. 15(1)(d)","description":"Envisaged storage period"},{"section":"Art. 15(1)(e)","description":"Right to rectification, erasure, restriction, objection"},{"section":"Art. 15(1)(f)","description":"Right to lodge complaint with supervisory authority"},{"section":"Art. 15(1)(g)","description":"Source of data"},{"section":"Art. 15(1)(h)","description":"Automated decision-making and profiling"},{"section":"Art. 15(3)","description":"Provision of copy — first copy free"},{"section":"Art. 15(4)","description":"Must not adversely affect rights of others"}]', '["DSAR_response","data_inventory","processing_record","ROPA","privacy_notice","consent_record","automated_decision_disclosure"]', '["privacy-data-protection-audit"]', 'EU Data Protection Authorities / European Data Protection Board', 1, 1, datetime('now'), datetime('now'));
